/* Night Flight design tokens — single source of truth for marketing + panel */

:root {
  color-scheme: dark;

  /* Base */
  --bg-base: #0a0e27;
  --bg-surface: #12173a;
  --bg-surface-hover: #171c42;

  /* Borders */
  --border-subtle: rgba(255, 255, 255, 0.08);
  --border-hover: rgba(255, 255, 255, 0.16);

  /* Accents */
  --accent-primary: #ff6b35;
  --accent-primary-hover: #ff7f52;
  --accent-blue: #3b82f6;
  --accent-purple: #8b5cf6;
  --accent-green: #22c55e;

  /* Soft accent fills */
  --accent-primary-soft: rgba(255, 107, 53, 0.14);
  --accent-blue-soft: rgba(59, 130, 246, 0.14);
  --accent-purple-soft: rgba(139, 92, 246, 0.14);
  --accent-green-soft: rgba(34, 197, 94, 0.12);

  /* Text */
  --text-primary: #f8fafc;
  --text-secondary: #cbd5e1;
  --text-muted: #94a3b8;
  --text-on-accent: #ffffff;

  /* Glow blobs (use as background layers) */
  --glow-blue: radial-gradient(circle, #3b82f6 0%, transparent 70%);
  --glow-purple: radial-gradient(circle, #8b5cf6 0%, transparent 70%);
  --glow-orange: radial-gradient(circle, #ff6b35 0%, transparent 70%);

  /* Elevation */
  --shadow-card: 0 8px 32px rgba(0, 0, 0, 0.24);
  --radius-card: 1rem;
  --radius-button: 0.5rem;
  --radius-pill: 9999px;

  /* Panel aliases — keep existing class names working */
  --bg: var(--bg-base);
  --bg-elevated: var(--bg-surface);
  --surface: var(--bg-surface);
  --surface2: var(--bg-surface-hover);
  --surface-hover: var(--bg-surface-hover);
  --border: var(--border-subtle);
  --border-strong: var(--border-hover);
  --text: var(--text-primary);
  --muted: var(--text-muted);
  --accent: var(--accent-primary);
  --accent-hover: var(--accent-primary-hover);
  --accent-soft: var(--accent-primary-soft);
  --success: var(--accent-green);
  --success-soft: var(--accent-green-soft);
  --warn: #f5a623;
  --warn-soft: rgba(245, 166, 35, 0.12);
  --danger: var(--text-muted);
  --danger-soft: rgba(148, 163, 184, 0.12);
  --referral: var(--accent-blue);
  --referral-soft: var(--accent-blue-soft);
  --visa: var(--accent-purple);
  --visa-soft: var(--accent-purple-soft);
  --brand-sky: var(--accent-blue);
  --brand-sky-soft: var(--accent-blue-soft);
  --brand-gradient: linear-gradient(
    135deg,
    var(--accent-primary) 0%,
    var(--accent-blue) 52%,
    var(--accent-purple) 100%
  );
  --brand-gradient-soft: linear-gradient(
    135deg,
    rgba(255, 107, 53, 0.18) 0%,
    rgba(59, 130, 246, 0.1) 48%,
    rgba(139, 92, 246, 0.14) 100%
  );
  --radius: var(--radius-card);
  --radius-sm: var(--radius-button);
  --radius-pill: 999px;
  --shadow: var(--shadow-card);
  --shadow-sm: 0 4px 16px rgba(0, 0, 0, 0.22);
}

