@import "../../relocation_jobs/static/design-tokens.css";
@import "tailwindcss/base";
@import "tailwindcss/components";
@import "tailwindcss/utilities";

html {
  scroll-behavior: smooth;
}

body {
  @apply font-sans font-normal text-text-primary antialiased;
  background:
    radial-gradient(ellipse 70% 45% at 85% 8%, rgba(59, 130, 246, 0.22), transparent 55%),
    radial-gradient(ellipse 55% 40% at 8% 90%, rgba(255, 107, 53, 0.14), transparent 50%),
    var(--bg-base);
  color: var(--text-primary);
}

/* ── Typography ── */

.text-fluid-hero {
  font-family: var(--font-display), var(--font-inter), system-ui, sans-serif;
  font-size: clamp(2.25rem, 4vw + 1rem, 3.5rem);
  font-weight: 800;
  letter-spacing: -0.03em;
  line-height: 1.1;
}

.text-section-title {
  font-family: var(--font-display), var(--font-inter), system-ui, sans-serif;
  font-size: clamp(1.5rem, 1.5vw + 1rem, 2rem);
  font-weight: 700;
  letter-spacing: -0.02em;
  line-height: 1.2;
}

.font-display {
  font-family: var(--font-display), var(--font-inter), system-ui, sans-serif;
}

/* ── Glass card ── */

.card {
  background: var(--bg-surface);
  border: 1px solid var(--border-subtle);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  box-shadow: var(--shadow-card);
}

.card-interactive {
  transition:
    transform 200ms ease-out,
    border-color 200ms ease-out,
    box-shadow 200ms ease-out;
}

.card-interactive:hover {
  border-color: var(--border-hover);
  transform: translateY(-2px);
}

/* Legacy aliases used during migration */
.surface-card {
  background: var(--bg-surface);
  border: 1px solid var(--border-subtle);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  box-shadow: var(--shadow-card);
}

.surface-card-interactive {
  transition:
    transform 200ms ease-out,
    border-color 200ms ease-out,
    box-shadow 200ms ease-out;
}

.surface-card-interactive:hover {
  border-color: var(--border-hover);
  transform: translateY(-2px);
}

/* ── Buttons ── */

.btn-primary {
  background: var(--accent-primary);
  color: var(--text-on-accent);
  border-radius: var(--radius-button);
  box-shadow: 0 2px 12px rgba(255, 107, 53, 0.28);
  transition:
    background 200ms ease-out,
    transform 200ms ease-out,
    box-shadow 200ms ease-out;
}

.btn-primary:hover {
  background: var(--accent-primary-hover);
  transform: scale(1.02);
  box-shadow: 0 4px 16px rgba(255, 107, 53, 0.34);
}

.btn-primary:active {
  transform: scale(0.99);
}

.btn-secondary {
  background: transparent;
  color: var(--text-primary);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-button);
  transition:
    border-color 200ms ease-out,
    background 200ms ease-out;
}

.btn-secondary:hover {
  border-color: var(--border-hover);
  background: rgba(255, 255, 255, 0.04);
}

/* ── Glow atmosphere ── */

.hero-search-glow {
  position: relative;
}

.hero-search-glow::before {
  content: "";
  position: absolute;
  inset: -40% -10% -30%;
  z-index: 0;
  background: var(--glow-blue);
  filter: blur(100px);
  opacity: 0.45;
  pointer-events: none;
}

.hero-search-glow > * {
  position: relative;
  z-index: 1;
}

.glow-orange {
  position: relative;
}

.glow-orange::before {
  content: "";
  position: absolute;
  inset: -30% -20%;
  z-index: 0;
  background: var(--glow-orange);
  filter: blur(100px);
  opacity: 0.4;
  pointer-events: none;
}

.glow-orange > * {
  position: relative;
  z-index: 1;
}

/* ── Form controls ── */

.select-pill {
  @apply w-full appearance-none rounded-lg border py-3 pl-10 pr-10 text-sm font-normal;
  color: var(--text-primary);
  border-color: var(--border-subtle);
  background: var(--bg-surface-hover);
  transition:
    border-color 200ms ease,
    box-shadow 200ms ease;
}

.select-pill:focus-visible {
  outline: none;
  border-color: var(--accent-primary);
  box-shadow:
    0 0 0 2px var(--bg-base),
    0 0 0 4px rgba(255, 107, 53, 0.45);
}

.select-icon {
  top: calc(50% + 0.5px);
  transform: translateY(-50%);
}

/* ── Focus rings ── */

:focus {
  outline: none;
}

:focus-visible {
  outline: none;
  box-shadow:
    0 0 0 2px var(--bg-base),
    0 0 0 4px rgba(255, 107, 53, 0.55);
}

.btn-primary:focus-visible {
  box-shadow:
    0 0 0 2px var(--bg-base),
    0 0 0 4px rgba(255, 107, 53, 0.72);
}

/* ── Section rhythm ── */

.section-major {
  padding-top: 3.5rem;
  padding-bottom: 3.5rem;
}

@media (min-width: 1024px) {
  .section-major {
    padding-top: 6rem;
    padding-bottom: 6rem;
  }
}

.section-major-first {
  padding-top: 2.5rem;
  padding-bottom: 3.5rem;
}

@media (min-width: 1024px) {
  .section-major-first {
    padding-top: 3.5rem;
    padding-bottom: 6rem;
  }
}

.section-compact {
  padding-top: 2rem;
  padding-bottom: 2rem;
}

/* ── Pill controls (nav, filters) ── */

.pill-control {
  @apply inline-flex items-center rounded-full px-3.5 py-1.5;
  color: color-mix(in srgb, var(--text-primary) 85%, transparent);
  border: 1px solid var(--border-subtle);
  background: var(--bg-surface);
  transition:
    border-color 200ms ease,
    color 200ms ease;
}

.pill-control:hover {
  border-color: var(--border-hover);
  color: var(--text-primary);
}

/* ── Sticky nav glass ── */

.nav-glass {
  background: color-mix(in srgb, var(--bg-base) 80%, transparent);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid var(--border-subtle);
}

/* ── Entrance (page load) ── */

@keyframes fade-up {
  from {
    opacity: 0;
    transform: translateY(16px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.hero-enter {
  animation: fade-up 400ms cubic-bezier(0.16, 1, 0.3, 1) both;
}

.hero-enter-delay-1 {
  animation-delay: 80ms;
}

.hero-enter-delay-2 {
  animation-delay: 160ms;
}

.hero-enter-delay-3 {
  animation-delay: 240ms;
}

/* ── Scroll reveal ── */

.reveal-card {
  transition:
    opacity 500ms cubic-bezier(0.16, 1, 0.3, 1),
    transform 500ms cubic-bezier(0.16, 1, 0.3, 1);
}

.reveal-card.reveal-pending:not(.is-visible) {
  opacity: 0;
  transform: translateY(12px);
}

.reveal-card.is-visible {
  opacity: 1;
  transform: translateY(0);
}

.reveal-card.card-interactive.is-visible:hover,
.reveal-card.surface-card-interactive.is-visible:hover {
  transform: translateY(-2px);
}

@keyframes pill-swap-in {
  from {
    opacity: 0;
    transform: translateY(3px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.alive-pill-swap {
  animation: pill-swap-in 320ms cubic-bezier(0.16, 1, 0.3, 1);
}

/* ── Reduced motion ── */

@media (prefers-reduced-motion: reduce) {
  html {
    scroll-behavior: auto;
  }

  .hero-enter,
  .hero-enter-delay-1,
  .hero-enter-delay-2,
  .hero-enter-delay-3 {
    animation: none;
  }

  .reveal-card.reveal-pending:not(.is-visible) {
    opacity: 1;
    transform: none;
    transition: none;
  }

  .reveal-card {
    transition: none;
  }

  .card-interactive,
  .surface-card-interactive {
    transition: border-color 200ms ease;
  }

  .card-interactive:hover,
  .surface-card-interactive:hover {
    transform: none;
  }

  .btn-primary:hover,
  .btn-primary:active {
    transform: none;
  }

  .alive-pill-swap {
    animation: none;
  }

  .hero-search-glow::before,
  .glow-orange::before {
    transition: none;
  }

  .btn-primary {
    transition: background 200ms ease;
  }
}

