import type { ButtonHTMLAttributes, ReactNode } from "react";

type ButtonVariant = "primary" | "secondary";

type ButtonProps = ButtonHTMLAttributes<HTMLButtonElement> & {
  variant?: ButtonVariant;
  children: ReactNode;
  className?: string;
  href?: string;
  as?: "button" | "a";
};

const VARIANT_CLASS: Record<ButtonVariant, string> = {
  primary:
    "btn-primary inline-flex items-center justify-center rounded-lg px-5 py-2.5 text-sm font-semibold text-text-on-accent",
  secondary:
    "btn-secondary inline-flex items-center justify-center rounded-lg px-5 py-2.5 text-sm font-semibold",
};

export function Button({
  variant = "primary",
  children,
  className = "",
  href,
  as,
  ...rest
}: ButtonProps) {
  const classes = `${VARIANT_CLASS[variant]} ${className}`;

  if (as === "a" || href) {
    return (
      <a href={href} className={classes}>
        {children}
      </a>
    );
  }

  return (
    <button type="button" className={classes} {...rest}>
      {children}
    </button>
  );
}

import type { ReactNode } from "react";

export type PillVariant =
  | "applied"
  | "awaiting"
  | "looking"
  | "rejected"
  | "not-for-me"
  | "referral"
  | "country"
  | "neutral"
  | "warn"
  | "visa";

const VARIANT_CLASSES: Record<PillVariant, string> = {
  applied:
    "border-[color-mix(in_srgb,var(--accent-green)_28%,transparent)] bg-[color-mix(in_srgb,var(--accent-green)_14%,transparent)] text-[var(--accent-green)]",
  awaiting:
    "border-[color-mix(in_srgb,var(--accent-purple)_28%,transparent)] bg-[color-mix(in_srgb,var(--accent-purple)_14%,transparent)] text-[var(--accent-purple)]",
  looking:
    "border-[color-mix(in_srgb,var(--accent-blue)_28%,transparent)] bg-[color-mix(in_srgb,var(--accent-blue)_14%,transparent)] text-[var(--accent-blue)]",
  rejected:
    "border-[var(--border-subtle)] bg-[color-mix(in_srgb,var(--text-muted)_10%,transparent)] text-[var(--text-muted)]",
  "not-for-me":
    "border-[color-mix(in_srgb,var(--warn)_28%,transparent)] bg-[color-mix(in_srgb,var(--warn)_12%,transparent)] text-[var(--warn)]",
  referral:
    "border-[color-mix(in_srgb,var(--accent-blue)_28%,transparent)] bg-[color-mix(in_srgb,var(--accent-blue)_14%,transparent)] text-[var(--accent-blue)]",
  country:
    "border-[color-mix(in_srgb,var(--accent-blue)_24%,transparent)] bg-[color-mix(in_srgb,var(--accent-blue)_12%,transparent)] text-[var(--accent-blue)]",
  neutral:
    "border-[var(--border-subtle)] bg-[color-mix(in_srgb,var(--text-muted)_8%,transparent)] text-[var(--text-muted)]",
  warn:
    "border-[color-mix(in_srgb,var(--warn)_28%,transparent)] bg-[color-mix(in_srgb,var(--warn)_12%,transparent)] text-[var(--warn)]",
  visa:
    "border-[color-mix(in_srgb,var(--accent-green)_28%,transparent)] bg-[color-mix(in_srgb,var(--accent-green)_14%,transparent)] text-[var(--accent-green)]",
};

type PillProps = {
  variant?: PillVariant;
  children: ReactNode;
  className?: string;
};

export function Pill({
  variant = "neutral",
  children,
  className = "",
}: PillProps) {
  return (
    <span
      className={`inline-flex items-center rounded-full border px-3 py-1 text-xs font-medium tracking-[0.02em] ${VARIANT_CLASSES[variant]} ${className}`}
    >
      {children}
    </span>
  );
}

import type { CSSProperties, ReactNode } from "react";

type CardVariant = "default" | "feature" | "company" | "testimonial";

type CardProps = {
  children: ReactNode;
  className?: string;
  style?: CSSProperties;
  accentBar?: boolean;
  interactive?: boolean;
  variant?: CardVariant;
  as?: "div" | "article" | "section";
};

export function Card({
  children,
  className = "",
  style,
  accentBar = false,
  interactive = false,
  variant = "default",
  as: Tag = "div",
}: CardProps) {
  const interactiveClass = interactive
    ? "card-interactive surface-card-interactive"
    : "";

  return (
    <Tag
      className={`card surface-card relative overflow-hidden rounded-2xl ${interactiveClass} ${className}`}
      style={style}
      data-variant={variant}
    >
      {accentBar ? (
        <span
          className="pointer-events-none absolute bottom-0 left-0 top-0 w-1 rounded-l-2xl bg-gradient-to-b from-accent-primary via-accent-blue to-accent-purple opacity-70"
          aria-hidden="true"
        />
      ) : null}
      {children}
    </Tag>
  );
}

type FeatureCardProps = {
  title: string;
  body: string;
  icon: ReactNode;
  chip?: ReactNode;
  className?: string;
  style?: CSSProperties;
};

export function FeatureCard({
  title,
